class Solution {
public:
    int numWays(int steps, int arrLen) {
        if (arrLen > steps / 2 + 1) arrLen = steps / 2 + 1;
        int mod = 1e9 + 7;
        vector<int> dp(steps + 1);
        dp[0] = 1;
        for (int i = 1; i <= steps; i++) {
            for (int j = 0; j <= i; j++) {
                if (j > 0) dp[i] = (dp[i] + dp[i - j]) % mod;
                if (j < i) dp[i] = (dp[i] + dp[j]) % mod;
            }
        }
        return dp[steps];
    }
};
